// frontend/src/hooks/useSerialSensor.js
import { useState, useCallback } from 'react';
import WebSerialService from '../services/webSerialService';

export const useSerialSensor = () => {
    const [status, setStatus] = useState({ connected: false });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [serialService, setSerialService] = useState(null);

    const connect = useCallback(async () => {
        setLoading(true);
        setError(null);
        
        try {
            const service = new WebSerialService();
            
            service.on('disconnected', () => {
                setStatus({ connected: false });
                setError('Device disconnected');
            });
            
            const result = await service.connect();
            
            if (result.success) {
                setSerialService(service);
                setStatus({ connected: true });
                return { success: true };
            } else {
                setError(result.error);
                return { success: false, error: result.error };
            }
        } catch (err) {
            setError(err.message);
            return { success: false, error: err.message };
        } finally {
            setLoading(false);
        }
    }, []);

    const disconnect = useCallback(() => {
        if (serialService) {
            serialService.disconnect();
            setSerialService(null);
            setStatus({ connected: false });
        }
    }, [serialService]);

    const scanFingerprint = useCallback(async () => {
        if (!serialService || !status.connected) {
            throw new Error('Not connected to device');
        }
        
        setLoading(true);
        try {
            return await serialService.scanFingerprint();
        } catch (err) {
            setError(err.message);
            throw err;
        } finally {
            setLoading(false);
        }
    }, [serialService, status.connected]);

    const enrollFingerprint = useCallback(async () => {
        if (!serialService || !status.connected) {
            throw new Error('Not connected to device');
        }
        
        setLoading(true);
        try {
            return await serialService.enrollFingerprint();
        } catch (err) {
            setError(err.message);
            throw err;
        } finally {
            setLoading(false);
        }
    }, [serialService, status.connected]);

    return {
        status,
        loading,
        error,
        connect,
        disconnect,
        scanFingerprint,
        enrollFingerprint,
        isSerialSupported: !!navigator.serial
    };
};
